
import Web3 from "web3";
import BallotContractBuild from 'contracts/Ballot.json'

let selectedAccount;

let ballotContract;

export let initialized = false;

export const Web3Client = async () => {
    let provider = window.ethereum;
    if (typeof provider !== 'undefined') {
        provider
            .request({ method: 'eth_requestAccounts' })
            .then(accounts => {
                selectedAccount = accounts[0]
                console.log(`selectedAccount is ${accounts[0]}`)
            })
            .catch((err) => {
                console.log(err)
                return
            });
        window.ethereum.on('accountsChanged', function (accounts) {
            console.log(`current account is ${accounts[0]}`)
        })
    }
    const web3 = new Web3(provider)
    
    if (!provider) {
        initialized = false;
        console.log('Web3 not avaible on this browser')
    } else {
        const networkId = await web3.eth.net.getId()
        ballotContract = new web3.eth.Contract(BallotContractBuild.abi, '0xc62dC58bA83Bfc7dD985C8aE6d2C0F087695c73B');
        initialized = true;
    }
}

export const userVoteYes = async () => {
    if (!initialized) {
        await Web3Client()
    }

    ballotContract.methods
    .vote(0)
    .send({ from: selectedAccount });
}

export const userVoteNo = async () => {
    if (!initialized) {
        await Web3Client()
    }

    ballotContract.methods
    .vote(1)
    .send({ from: selectedAccount });

    console.log(ballotContract.methods.proposals)
}

export const whoWon = async () => {
    if (!initialized) {
        await Web3Client()
    }

    console.log(ballotContract.methods
    .winnerName()
    .send({ from: selectedAccount }))
}

export const deployContract = async () => {
    if (!initialized) {
        await Web3Client()
    }
    ballotContract.deploy({
        data: "",
        arguments: ['yes', 'no']
    })
}
